#!/usr/bin/env python3
# Generated by OpenCode on 2026-04-28
"""Quality checker for knowledge entry JSON files.

Evaluates knowledge entries across 5 dimensions and assigns a grade.
"""

import json
import sys
from dataclasses import dataclass, field
from pathlib import Path


# ---------------------------------------------------------------------------
# Constants
# ---------------------------------------------------------------------------
SUMMARY_MAX_SCORE = 25
TECH_DEPTH_MAX_SCORE = 25
FORMAT_MAX_SCORE = 20
TAGS_MAX_SCORE = 15
BUZZ_MAX_SCORE = 15

